Add two new `Set<string>` fields to the `ToolState` interface and `createToolState()` factory to enable deduplication of tool results and detection of missing tool input.

## Implementation Steps

### 1. Update `apps/server/src/services/runtimes/claude-code/agent-types.ts`

**Add two new fields to the `ToolState` interface** after the `toolNameById` field (line 32):

```typescript
/** Mutable tool tracking state passed by reference into the event mapper. */
export interface ToolState {
  inTool: boolean;
  currentToolName: string;
  currentToolId: string;
  taskToolInput: string;
  inThinking: boolean;
  thinkingStartMs: number;
  /** Lookup table mapping tool_use block IDs to tool names for result correlation. */
  toolNameById: Map<string, string>;
  /** Tool IDs whose results were already delivered via tool_use_summary. */
  resolvedResultIds: Set<string>;
  /** Tool IDs that received at least one input_json_delta during streaming. */
  toolInputReceived: Set<string>;
  appendTaskInput: (chunk: string) => void;
  resetTaskInput: () => void;
  setToolState: (tool: boolean, name: string, id: string) => void;
}
```

**Update `createToolState()` to initialize both sets** — add after the `toolNameById` initialization (line 46):

```typescript
export function createToolState(): ToolState {
  let inTool = false;
  let currentToolName = '';
  let currentToolId = '';
  let taskToolInput = '';
  let inThinking = false;
  let thinkingStartMs = 0;
  const toolNameById = new Map<string, string>();
  const resolvedResultIds = new Set<string>();
  const toolInputReceived = new Set<string>();
  return {
    get inTool() {
      return inTool;
    },
    get currentToolName() {
      return currentToolName;
    },
    get currentToolId() {
      return currentToolId;
    },
    get taskToolInput() {
      return taskToolInput;
    },
    get inThinking() {
      return inThinking;
    },
    set inThinking(v: boolean) {
      inThinking = v;
    },
    get thinkingStartMs() {
      return thinkingStartMs;
    },
    set thinkingStartMs(v: number) {
      thinkingStartMs = v;
    },
    toolNameById,
    resolvedResultIds,
    toolInputReceived,
    appendTaskInput: (chunk: string) => {
      taskToolInput += chunk;
    },
    resetTaskInput: () => {
      taskToolInput = '';
    },
    setToolState: (tool: boolean, name: string, id: string) => {
      inTool = tool;
      currentToolName = name;
      currentToolId = id;
    },
  };
}
```

### 2. Update test helper `makeToolState()` in `apps/server/src/services/core/__tests__/sdk-event-mapper.test.ts`

The existing `makeToolState()` function (lines 52-83) must also expose the new fields, otherwise TypeScript will not compile since it returns a value typed as `ToolState`:

```typescript
function makeToolState(): ToolState {
  let inTool = false;
  let currentToolName = '';
  let currentToolId = '';
  let taskToolInput = '';
  return {
    get inTool() {
      return inTool;
    },
    get currentToolName() {
      return currentToolName;
    },
    get currentToolId() {
