    },
    get taskToolInput() {
      return taskToolInput;
    },
    toolNameById: new Map<string, string>(),
    resolvedResultIds: new Set<string>(),
    toolInputReceived: new Set<string>(),
    appendTaskInput: (chunk: string) => {
      taskToolInput += chunk;
    },
    resetTaskInput: () => {
      taskToolInput = '';
