    setToolState: (tool: boolean, name: string, id: string) => {
      inTool = tool;
      currentToolName = name;
      currentToolId = id;
    },
  };
}
```

Note: the test helper does not need the `inThinking` / `thinkingStartMs` getters/setters because the ToolState type already declares them as plain properties with get/set.

## Acceptance Criteria

- `ToolState` interface includes `resolvedResultIds: Set<string>` and `toolInputReceived: Set<string>`
- `createToolState()` returns an object with both sets initialized as `new Set<string>()`
- Test helper `makeToolState()` also includes both new fields
- TypeScript compiles cleanly: `pnpm typecheck`
- Existing tests still pass: `pnpm vitest run apps/server/src/services/core/__tests__/sdk-event-mapper.test.ts`

Modify two existing handlers in `sdk-event-mapper.ts` to populate the new ToolState tracking sets. These changes are prerequisites for the new MCP result and input backfill handlers in Phase 3.

## Implementation Steps

### 1. Mark resolved IDs in `tool_use_summary` handler (`apps/server/src/services/runtimes/claude-code/sdk-event-mapper.ts`)

In the existing `tool_use_summary` handler (line 294), add `toolState.resolvedResultIds.add(toolUseId)` inside the `for` loop, **before** the `yield` statement. This ensures that when a user message later arrives with the same tool_use_id, the result is not emitted again.

The handler currently reads:

```typescript
if (message.type === 'tool_use_summary') {
  const summary = message as { summary: string; preceding_tool_use_ids: string[] };
  for (const toolUseId of summary.preceding_tool_use_ids) {
    yield {
      type: 'tool_result',
      data: {
        toolCallId: toolUseId,
        toolName: toolState.toolNameById.get(toolUseId) ?? '',
        result: summary.summary,
        status: 'complete',
      },
    };
  }
  return;
}
```

Change it to:

```typescript
if (message.type === 'tool_use_summary') {
  const summary = message as { summary: string; preceding_tool_use_ids: string[] };
  for (const toolUseId of summary.preceding_tool_use_ids) {
    toolState.resolvedResultIds.add(toolUseId);
    yield {
      type: 'tool_result',
      data: {
        toolCallId: toolUseId,
        toolName: toolState.toolNameById.get(toolUseId) ?? '',
        result: summary.summary,
        status: 'complete',
      },
    };
  }
  return;
}
```

### 2. Track `input_json_delta` reception (same file)

In the `input_json_delta` handler (line 228), add `toolState.toolInputReceived.add(toolState.currentToolId)` before the existing logic. This records that at least one input delta was received for this tool call, so the assistant message input backfill handler in Phase 3 knows to skip it.

The handler currently reads:

```typescript
} else if (delta?.type === 'input_json_delta' && toolState.inTool) {
  if (TASK_TOOL_NAMES.has(toolState.currentToolName)) {
    toolState.appendTaskInput(delta.partial_json as string);
  }
  yield {
    type: 'tool_call_delta',
    data: {
      toolCallId: toolState.currentToolId,
      toolName: toolState.currentToolName,
      input: delta.partial_json as string,
      status: 'running',
    },
  };
}
```

Change it to:

```typescript
} else if (delta?.type === 'input_json_delta' && toolState.inTool) {
  toolState.toolInputReceived.add(toolState.currentToolId);
  if (TASK_TOOL_NAMES.has(toolState.currentToolName)) {
    toolState.appendTaskInput(delta.partial_json as string);
  }
  yield {
    type: 'tool_call_delta',
    data: {
      toolCallId: toolState.currentToolId,
      toolName: toolState.currentToolName,
      input: delta.partial_json as string,
      status: 'running',
    },
  };
}
```

## Acceptance Criteria

- When `tool_use_summary` fires, each `toolUseId` in `preceding_tool_use_ids` is added to `toolState.resolvedResultIds` before the `tool_result` event is yielded
- When `input_json_delta` fires, `toolState.currentToolId` is added to `toolState.toolInputReceived`
- Existing `tool_use_summary` and `input_json_delta` test cases still pass unchanged — the new tracking is additive and does not alter the yielded events
- All existing tests pass: `pnpm vitest run apps/server/src/services/core/__tests__/sdk-event-mapper.test.ts`
- TypeScript compiles: `pnpm typecheck`

Add a new handler in `sdk-event-mapper.ts` for `message.type === 'assistant'` that backfills tool input for MCP tools where no `input_json_delta` events were received during streaming. This fixes the secondary issue where MCP tools with empty `{}` input show no input in the streamed ToolCallCard.

## Implementation Steps

### 1. Add assistant message handler in `apps/server/src/services/runtimes/claude-code/sdk-event-mapper.ts`

Insert this handler **before** the `tool_use_summary` handler (before the `if (message.type === 'tool_use_summary')` block, currently at line 294). Place it after the `stream_event` block's closing `return;` (line 290):

```typescript
// Backfill tool input from completed assistant message (for MCP tools with empty input)
if (message.type === 'assistant') {
  const content = (message as Record<string, unknown>).message;
  const contentBlocks = (content as Record<string, unknown>)?.content;
  if (Array.isArray(contentBlocks)) {
    for (const block of contentBlocks as Array<Record<string, unknown>>) {
      if (
        block.type === 'tool_use' &&
        typeof block.id === 'string' &&
        !toolState.toolInputReceived.has(block.id) &&
        toolState.toolNameById.has(block.id)
      ) {
        const inputStr = JSON.stringify(block.input ?? {});
        yield {
          type: 'tool_call_delta',
          data: {
            toolCallId: block.id,
            toolName: toolState.toolNameById.get(block.id) ?? '',
            input: inputStr,
            status: 'running',
          },
        };
      }
    }
  }
  return;
}
```

**How this works:**

1. When the SDK emits an `assistant` message, it contains the full `message.content` array with `tool_use` blocks that include the final `input` object.
2. For each `tool_use` block, we check if its ID is NOT in `toolState.toolInputReceived` — meaning no `input_json_delta` events were streamed for this tool call.
3. We also check that the tool ID exists in `toolState.toolNameById` — meaning we saw a `content_block_start` for it (it is a known tool call, not a stale reference).
4. If both conditions are met, we emit a `tool_call_delta` with the serialized input, filling the gap that the missing `input_json_delta` left.
5. The `JSON.stringify(block.input ?? {})` ensures we always get at least `'{}'` for empty inputs.

**Why this is a file-local approach:** The `assistant` message from the SDK uses loosely-typed SDK message objects (not the strongly-typed `ContentBlock` from `transcript-parser.ts`), so we use `Record<string, unknown>` casts throughout.

## Acceptance Criteria

- An `assistant` message containing `tool_use` blocks where no `input_json_delta` was previously received yields a `tool_call_delta` SSE event with the serialized input
- An `assistant` message containing `tool_use` blocks where `input_json_delta` WAS received yields NO additional `tool_call_delta` events
- The `tool_call_delta` event includes the correct `toolCallId`, `toolName`, and `input` fields
- For empty-input MCP tools, the input string is `'{}'`
- For non-empty-input MCP tools that somehow missed deltas, the full serialized input is emitted
- TypeScript compiles: `pnpm typecheck`

Add a new handler in `sdk-event-mapper.ts` for `message.type === 'user'` that extracts `tool_result` content blocks from SDK user messages and emits `tool_result` SSE events. This is the primary fix — it delivers MCP tool results to the client during live streaming.

## Implementation Steps

### 1. Add `extractToolResultText` file-local helper in `apps/server/src/services/runtimes/claude-code/sdk-event-mapper.ts`

Add this helper function at the **top** of the file, after the imports and before the `TOOL_CONTEXTUAL_HOOK_EVENTS` constant (before line 8). This mirrors the logic from `extractToolResultContent` in `transcript-parser.ts` but works with loosely-typed SDK message objects:

```typescript
/** Extract text from a tool_result content field (file-local, loosely-typed for SDK messages). */
function extractToolResultText(content: unknown): string {
  if (!content) return '';
  if (typeof content === 'string') return content;
  if (!Array.isArray(content)) return '';
  return (content as Array<Record<string, unknown>>)
    .filter((b) => b.type === 'text' && b.text)
    .map((b) => b.text as string)
    .join('\n');
}
```

**Why file-local instead of importing from `transcript-parser.ts`:** The `transcript-parser.ts` version uses a `ContentBlock` type from its own module scope with specific type narrowing. The event mapper works with `Record<string, unknown>` casts from SDK messages. Sharing would create coupling between two modules with different type philosophies. The logic is 7 lines — duplication is acceptable.

### 2. Add user message handler (same file)

Insert this handler **after** the assistant message handler (from task 3.1) and **before** the `tool_use_summary` handler:

```typescript
// Extract tool results from user messages (MCP tools deliver results here, not via tool_use_summary)
if (message.type === 'user') {
  // Skip replay messages during session resume
  if ((message as Record<string, unknown>).isReplay) return;

  const content = (message as Record<string, unknown>).message;
  const contentBlocks = (content as Record<string, unknown>)?.content;
  if (Array.isArray(contentBlocks)) {
    for (const block of contentBlocks as Array<Record<string, unknown>>) {
      if (block.type === 'tool_result' && typeof block.tool_use_id === 'string') {
        // Skip tools already resolved via tool_use_summary (built-in tools)
        if (toolState.resolvedResultIds.has(block.tool_use_id)) continue;

        const resultText = extractToolResultText(block.content);
        if (resultText) {
          yield {
            type: 'tool_result',
            data: {
              toolCallId: block.tool_use_id,
              toolName: toolState.toolNameById.get(block.tool_use_id) ?? '',
              result: resultText,
              status: 'complete',
            },
          };
        }
      }
    }
  }
  return;
}
```

**How this works:**

1. **Replay guard:** `isReplay: true` is set by the SDK on messages replayed during session resume. We skip these to avoid re-emitting stale tool results to the client.
2. **Content extraction:** The SDK `user` message has shape `{ type: 'user', message: { role: 'user', content: [...] } }`. The `content` array contains `tool_result` blocks with `tool_use_id` and `content` fields.
3. **Deduplication:** We check `toolState.resolvedResultIds` — if the tool ID was already resolved via `tool_use_summary` (for built-in tools), we skip it. This prevents duplicate results.
4. **Text extraction:** `extractToolResultText` handles the three content formats: `string` (plain text), `Array<{type: 'text', text: string}>` (content blocks), or `undefined`/`null` (no content).
5. **Empty results:** If `resultText` is empty string, we do NOT yield an event (nothing useful to show).

**Data flow after both Phase 3 handlers are in place:**

```
SDK stream
  ├─ stream_event: content_block_start → tool_call_start SSE (unchanged)
  ├─ stream_event: input_json_delta    → tool_call_delta SSE (unchanged)
  ├─ stream_event: content_block_stop  → tool_call_end SSE (unchanged)
  ├─ assistant message                 → tool_call_delta SSE [NEW: input backfill]
  ├─ user message (tool_result blocks) → tool_result SSE [NEW: MCP results]
  ├─ tool_use_summary                  → tool_result SSE (unchanged, built-in only)
  └─ result                            → session_status + done SSE (unchanged)
```

## Acceptance Criteria

- SDK `user` messages containing `tool_result` blocks yield `tool_result` SSE events for each unresolved tool call
- SDK `user` messages with `isReplay: true` yield NO events (replay guard)
- Tool IDs already in `toolState.resolvedResultIds` (from `tool_use_summary`) are skipped (deduplication)
- `tool_result` SSE events include correct `toolCallId`, `toolName`, `result`, and `status: 'complete'`
- Empty result content yields no event
- `extractToolResultText` correctly handles: string content, array of text blocks, mixed content blocks (filters non-text), null/undefined content
- TypeScript compiles: `pnpm typecheck`

Add a new scenario builder function to `sdk-scenarios.ts` that produces the full SDK event sequence for an MCP tool call. This enables end-to-end testing of the MCP tool result streaming pipeline.

## Implementation Steps

### 1. Add `sdkMcpToolCall` to `apps/server/src/services/runtimes/claude-code/__tests__/sdk-scenarios.ts`

Add this new scenario builder after the existing `sdkTodoWrite` function (line 188). The MCP tool call sequence differs from built-in tools: it includes an `assistant` message (with `tool_use` blocks) and a `user` message (with `tool_result` blocks) but does NOT include a `tool_use_summary`.

```typescript
/**
 * Produces a full MCP tool call sequence: content_block_start → optional
 * input_json_delta → content_block_stop → assistant message → user message
 * with tool_result. Unlike built-in tools, MCP tools do NOT emit
 * tool_use_summary.
 *
 * @param toolName - MCP tool name (e.g., 'mcp__dorkos__mesh_list')
 * @param toolId - Unique tool use ID
 * @param input - Tool input object (empty `{}` to test the empty-input case)
 * @param resultContent - Tool result text content
 */
export async function* sdkMcpToolCall(
  toolName: string,
  toolId: string,
  input: object,
  resultContent: string
): AsyncGenerator<SDKMessage> {
  yield makeInit();

  // content_block_start — tool_use
  yield {
    type: 'stream_event',
    event: {
      type: 'content_block_start',
      index: 0,
      content_block: { type: 'tool_use', id: toolId, name: toolName, input: {} },
    },
    parent_tool_use_id: null,
    session_id: SESSION_ID,
    uuid: BASE_UUID,
  } as SDKMessage;

  // input_json_delta — only if input is non-empty
  const hasInput = Object.keys(input).length > 0;
  if (hasInput) {
    yield {
      type: 'stream_event',
      event: {
        type: 'content_block_delta',
        index: 0,
        delta: { type: 'input_json_delta', partial_json: JSON.stringify(input) },
      },
      parent_tool_use_id: null,
      session_id: SESSION_ID,
      uuid: BASE_UUID,
    } as SDKMessage;
  }

  // content_block_stop
  yield {
    type: 'stream_event',
    event: { type: 'content_block_stop', index: 0 },
    parent_tool_use_id: null,
    session_id: SESSION_ID,
    uuid: BASE_UUID,
  } as SDKMessage;

  // assistant message — contains the full tool_use block with resolved input
  yield {
    type: 'assistant',
    message: {
      role: 'assistant',
      content: [
        {
          type: 'tool_use',
          id: toolId,
          name: toolName,
          input,
        },
      ],
    },
    session_id: SESSION_ID,
    uuid: BASE_UUID,
  } as SDKMessage;

  // user message — contains tool_result blocks (MCP results arrive here)
  yield {
    type: 'user',
    message: {
      role: 'user',
      content: [
        {
          type: 'tool_result',
          tool_use_id: toolId,
          content: [
            {
              type: 'text',
              text: resultContent,
            },
          ],
        },
      ],
    },
    session_id: SESSION_ID,
    uuid: BASE_UUID,
  } as SDKMessage;

  yield makeResult();
}
```

### 2. Also add a helper for replay user messages

Add a standalone helper that creates a user message with `isReplay: true` for testing the replay guard:

```typescript
/**
 * Produces a user message with `isReplay: true` for testing the replay guard.
 *
 * @param toolId - Tool use ID to reference in the tool_result block
 * @param resultContent - Tool result text
 */
export function sdkReplayUserMessage(toolId: string, resultContent: string): SDKMessage {
  return {
    type: 'user',
    isReplay: true,
    message: {
      role: 'user',
      content: [
        {
          type: 'tool_result',
          tool_use_id: toolId,
          content: [
            {
              type: 'text',
              text: resultContent,
            },
          ],
        },
      ],
    },
    session_id: SESSION_ID,
    uuid: BASE_UUID,
  } as SDKMessage;
}
```

## Acceptance Criteria

- `sdkMcpToolCall` produces the correct event sequence: init → content_block_start → optional input_json_delta → content_block_stop → assistant message → user message → result
- When `input` is `{}` (empty), no `input_json_delta` event is yielded (simulating the empty-input case)
- When `input` has properties, an `input_json_delta` event is yielded with the serialized input
- The assistant message contains a `tool_use` block with the full input
- The user message contains a `tool_result` block with text content
- `sdkReplayUserMessage` produces a user message with `isReplay: true`
- TypeScript compiles: `pnpm typecheck`

Add at least 6 new test cases to `sdk-event-mapper.test.ts` covering MCP tool results, deduplication, input backfill, replay guard, and mixed tool call scenarios.

## Implementation Steps

### 1. Add new test cases in `apps/server/src/services/core/__tests__/sdk-event-mapper.test.ts`

Add a new `describe` block after the existing `tool_use_summary messages` describe block (line 264). These tests exercise the new handlers added in Phase 3.

```typescript
describe('MCP tool result streaming', () => {
  it('emits tool_result from user message for MCP tools', async () => {
    // Setup: simulate content_block_start to register the tool in toolNameById
    const toolState = makeToolState();
    const session = makeSession();

    // First, register the tool via content_block_start
    await collectEvents(
      mapSdkMessage(
        {
          type: 'stream_event',
          event: {
            type: 'content_block_start',
            index: 0,
            content_block: {
              type: 'tool_use',
              id: 'mcp-tc-1',
              name: 'mcp__dorkos__mesh_list',
              input: {},
            },
          },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    // Then, send the user message with tool_result
    const events = await collectEvents(
      mapSdkMessage(
        {
          type: 'user',
          message: {
            role: 'user',
            content: [
              {
                type: 'tool_result',
                tool_use_id: 'mcp-tc-1',
                content: [
                  { type: 'text', text: '{"agents":[{"name":"agent-1"}]}' },
                ],
              },
            ],
          },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('tool_result');
    expect((events[0].data as Record<string, unknown>).toolCallId).toBe('mcp-tc-1');
    expect((events[0].data as Record<string, unknown>).toolName).toBe(
      'mcp__dorkos__mesh_list'
    );
    expect((events[0].data as Record<string, unknown>).result).toBe(
      '{"agents":[{"name":"agent-1"}]}'
    );
    expect((events[0].data as Record<string, unknown>).status).toBe('complete');
  });

  it('deduplicates tool_result when tool_use_summary already fired', async () => {
    const toolState = makeToolState();
    const session = makeSession();

    // Register tool
    await collectEvents(
      mapSdkMessage(
        {
          type: 'stream_event',
          event: {
            type: 'content_block_start',
            index: 0,
            content_block: {
              type: 'tool_use',
              id: 'builtin-tc-1',
              name: 'Read',
              input: {},
            },
          },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    // tool_use_summary fires for built-in tool (adds to resolvedResultIds)
    await collectEvents(
      mapSdkMessage(
        {
          type: 'tool_use_summary',
          summary: 'File contents here',
          preceding_tool_use_ids: ['builtin-tc-1'],
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    // User message arrives with the same tool ID
    const events = await collectEvents(
      mapSdkMessage(
        {
          type: 'user',
          message: {
            role: 'user',
            content: [
              {
                type: 'tool_result',
                tool_use_id: 'builtin-tc-1',
                content: [{ type: 'text', text: 'File contents here' }],
              },
            ],
          },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    // Should yield nothing — already resolved via tool_use_summary
    expect(events).toHaveLength(0);
  });

  it('backfills tool input from assistant message when no input_json_delta was received', async () => {
    const toolState = makeToolState();
    const session = makeSession();

    // Register tool via content_block_start (no input_json_delta follows)
    await collectEvents(
      mapSdkMessage(
        {
          type: 'stream_event',
          event: {
            type: 'content_block_start',
            index: 0,
            content_block: {
              type: 'tool_use',
              id: 'mcp-tc-2',
              name: 'mcp__dorkos__mesh_list',
              input: {},
            },
          },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    // content_block_stop (no input_json_delta in between)
    await collectEvents(
      mapSdkMessage(
        {
          type: 'stream_event',
          event: { type: 'content_block_stop', index: 0 },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    // Assistant message with the full tool_use block
    const events = await collectEvents(
      mapSdkMessage(
        {
          type: 'assistant',
          message: {
            role: 'assistant',
            content: [
              {
                type: 'tool_use',
                id: 'mcp-tc-2',
                name: 'mcp__dorkos__mesh_list',
                input: {},
              },
            ],
          },
        } as unknown,
        session,
        'session-1',
        toolState
      )
    );

    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('tool_call_delta');
    expect((events[0].data as Record<string, unknown>).toolCallId).toBe('mcp-tc-2');
    expect((events[0].data as Record<string, unknown>).input).toBe('{}');
  });

  it('skips input backfill when input_json_delta was already received', async () => {
